import React, { useState, useEffect } from 'react';
import Home from './Home';
import FarmerAdd from './FarmerAdd';
import BuyerBrowse from './BuyerBrowse';

function App() {
  const [screen, setScreen] = useState('home');
  const [products, setProducts] = useState([]);

  // Load products from Backend when app starts
  useEffect(() => {
    fetch('http://127.0.0.1:5000/api/products')
      .then(res => res.json())
      .then(data => setProducts(data));
  }, [screen]);

  const saveCrop = (newCrop) => {
    fetch('http://127.0.0.1:5000/api/products', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newCrop)
    }).then(() => setScreen('home'));
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {screen === 'home' && (
        <Home 
          onSellClick={() => setScreen('sell')} 
          onBuyClick={() => setScreen('buy')} 
        />
      )}
      {screen === 'sell' && (
        <FarmerAdd 
          onBack={() => setScreen('home')} 
          onFinish={(data) => saveCrop(data)} 
        />
      )}
      {screen === 'buy' && (
        <BuyerBrowse 
          onBack={() => setScreen('home')} 
          items={products}
        />
      )}
    </div>
  );
}

export default App;
